89: void Mutations::mutateRequestHeaders(Http::RequestHeaderMap& headers,
90:                                      const Formatter::HttpFormatterContext& context,
91:                                      const StreamInfo::StreamInfo& stream_info) const {
92:   request_mutations_->evaluateHeaders(headers, context, stream_info);
93: 
94:   if (query_query_parameter_mutations_.empty() || headers.Path() == nullptr) {
95:     return;
96:   }
97: 
98:   // Mutate query parameters.
99:   Http::Utility::QueryParamsMulti params =
100:       Http::Utility::QueryParamsMulti::parseAndDecodeQueryString(headers.getPathValue());
101:   for (const auto& mutation : query_query_parameter_mutations_) {
102:     mutation->mutateQueryParameter(params, context, stream_info);
103:   }
104:   headers.setPath(params.replaceQueryString(headers.Path()->value()));
105: }
