107: void Mutations::mutateResponseHeaders(Http::ResponseHeaderMap& headers,
108:                                       const Formatter::HttpFormatterContext& context,
109:                                       const StreamInfo::StreamInfo& stream_info) const {
110:   response_mutations_->evaluateHeaders(headers, context, stream_info);
111: }
