113: PerRouteHeaderMutation::PerRouteHeaderMutation(const PerRouteProtoConfig& config,
114:                                                absl::Status& creation_status)
115:     : mutations_(config.mutations(), creation_status) {}
116: 
117: HeaderMutationConfig::HeaderMutationConfig(const ProtoConfig& config, absl::Status& creation_status)
118:     : mutations_(config.mutations(), creation_status),
119:       most_specific_header_mutations_wins_(config.most_specific_header_mutations_wins()) {}
120: 
121: void HeaderMutation::maybeInitializeRouteConfigs(Http::StreamFilterCallbacks* callbacks) {
122:   // Ensure that route configs are initialized only once and the same route configs are used
123:   // for both decoding and encoding paths.
124:   // An independent flag is used to ensure even at the case where the route configs is empty,
125:   // we still won't try to initialize it again.
126:   if (route_configs_initialized_) {
127:     return;
128:   }
129:   route_configs_initialized_ = true;
130: 
131:   // Traverse through all route configs to retrieve all available header mutations.
132:   // `getAllPerFilterConfig` returns in ascending order of specificity (i.e., route table
133:   // first, then virtual host, then per route).
134:   route_configs_ = Http::Utility::getAllPerFilterConfig<PerRouteHeaderMutation>(callbacks);
135: 
136:   // The order of returned route configs is route table first, then virtual host, then
137:   // per route. That means the per route configs will be evaluated at the end and will
138:   // override the more general virtual host and route table configs.
139:   //
140:   // So, if most_specific_header_mutations_wins is false, we need to reverse the order
141:   // of route configs.
142:   if (!config_->mostSpecificHeaderMutationsWins()) {
143:     std::reverse(route_configs_.begin(), route_configs_.end());
144:   }
145: }
146: 
147: Http::FilterHeadersStatus HeaderMutation::decodeHeaders(Http::RequestHeaderMap& headers, bool) {
148:   Formatter::HttpFormatterContext context{&headers};
149:   config_->mutations().mutateRequestHeaders(headers, context, decoder_callbacks_->streamInfo());
150: 
151:   maybeInitializeRouteConfigs(decoder_callbacks_);
152: 
153:   for (const PerRouteHeaderMutation& route_config : route_configs_) {
154:     route_config.mutations().mutateRequestHeaders(headers, context,
155:                                                   decoder_callbacks_->streamInfo());
156:   }
157: 
158:   return Http::FilterHeadersStatus::Continue;
159: }
160: 
161: Http::FilterHeadersStatus HeaderMutation::encodeHeaders(Http::ResponseHeaderMap& headers, bool) {
162:   Formatter::HttpFormatterContext context{encoder_callbacks_->requestHeaders().ptr(), &headers};
163:   config_->mutations().mutateResponseHeaders(headers, context, encoder_callbacks_->streamInfo());
164: 
165:   // Note if the filter before this one has send local reply then the decodeHeaders() will not be
166:   // be called and the route config will not be initialized. Try it again here and it will be
167:   // no-op if already initialized.
168:   maybeInitializeRouteConfigs(encoder_callbacks_);
169: 
170:   for (const PerRouteHeaderMutation& route_config : route_configs_) {
171:     route_config.mutations().mutateResponseHeaders(headers, context,
172:                                                    encoder_callbacks_->streamInfo());
173:   }
174: 
175:   return Http::FilterHeadersStatus::Continue;
176: }
177: 
178: } // namespace HeaderMutation
179: } // namespace HttpFilters
180: } // namespace Extensions
181: } // namespace Envoy
