    13→Config::Config(const ProtoConfig& proto_config, const bool per_route) {
    14→  // Process request rules
    15→  for (const auto& rule : proto_config.request_rules()) {
    16→    request_rules_.push_back(rule);
    17→  }
    18→
    19→  // Process response rules
    20→  for (const auto& rule : proto_config.response_rules()) {
    21→    response_rules_.push_back(rule);
    22→  }
    23→
    24→  // Note: empty configs are fine for the global config, which would be the case for enabling
    25→  // the filter globally without rules and then applying them at the virtual host or
    26→  // route level. At the virtual or route level, it makes no sense to have an empty
    27→  // config so we throw an error.
    28→  if (per_route && request_rules_.empty() && response_rules_.empty()) {
    29→    throw EnvoyException("custom_header_injection_filter: Per filter configs must at least specify "
    30→                         "either request or response rules");
    31→  }
    32→}
    33→
    34→CustomHeaderInjectionFilter::CustomHeaderInjectionFilter(const ConfigSharedPtr config)
    35→    : config_(config) {}
    36→
    37→CustomHeaderInjectionFilter::~CustomHeaderInjectionFilter() = default;
    38→
    39→Http::FilterHeadersStatus CustomHeaderInjectionFilter::decodeHeaders(Http::RequestHeaderMap& headers,
    40→                                                                     bool) {
    41→  const auto* config = getConfig();
    42→  if (config->hasRequestRules()) {
    43→    injectHeaders(headers, config->requestRules());
    44→  }
    45→
    46→  return Http::FilterHeadersStatus::Continue;
    47→}
    48→
    49→void CustomHeaderInjectionFilter::setDecoderFilterCallbacks(
    50→    Http::StreamDecoderFilterCallbacks& callbacks) {
    51→  decoder_callbacks_ = &callbacks;
    52→}
    53→
    54→Http::FilterHeadersStatus CustomHeaderInjectionFilter::encodeHeaders(Http::ResponseHeaderMap& headers,
    55→                                                                     bool) {
    56→  const auto* config = getConfig();
    57→  if (config->hasResponseRules()) {
    58→    injectHeaders(headers, config->responseRules());
    59→  }
    60→
    61→  return Http::FilterHeadersStatus::Continue;
    62→}
    63→
    64→void CustomHeaderInjectionFilter::setEncoderFilterCallbacks(
    65→    Http::StreamEncoderFilterCallbacks& callbacks) {
    66→  encoder_callbacks_ = &callbacks;
    67→}
    68→
    69→void CustomHeaderInjectionFilter::injectHeaders(Http::HeaderMap& headers,
    70→                                               const std::vector<HeaderInjectionRule>& rules) {
    71→  for (const auto& rule : rules) {
    72→    const auto header_name = Http::LowerCaseString(rule.header_name());
    73→    const auto& header_value = rule.header_value();
    74→
    75→    if (!header_value.empty()) {
    76→      headers.addCopy(header_name, header_value);
    77→    }
    78→  }
    79→}
    80→
    81→const Config* CustomHeaderInjectionFilter::getConfig() const {
    82→  // Cached config pointer.
    83→  if (effective_config_) {
    84→    return effective_config_;
    85→  }
    86→
    87→  effective_config_ = Http::Utility::resolveMostSpecificPerFilterConfig<Config>(decoder_callbacks_);
    88→  if (effective_config_) {
    89→    return effective_config_;
    90→  }
    91→
    92→  effective_config_ = config_.get();
    93→  return effective_config_;
    94→}
    95→
    96→} // namespace CustomHeaderInjection
    97→} // namespace HttpFilters
    98→} // namespace Extensions
